import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import './edit-profile.css';

function EditProfile() {
  const [profile, setProfile] = useState({
    fullName: '',
    email: '',
    mobileNumber: '',
    username: '',
    password: '********' // For display only
  });

  const [errors, setErrors] = useState({});
  const [message, setMessage] = useState(null);

  useEffect(() => {
    // Fetch profile data
    const defaultProfile = {
      fullName: 'Guest User',
      email: 'guest@example.com',
      mobileNumber: '',
      username: 'guestuser',
      password: '********'
    };

    setProfile(defaultProfile);

    // In a real app, you would fetch from API
    fetch('/api/profile')
      .then(response => {
        if (!response.ok) {
          throw new Error(`Failed to fetch profile: ${response.status}`);
        }
        return response.json();
      })
      .then(data => {
        // Add password placeholder to the data
        setProfile({...data, password: '********'});
      })
      .catch(err => {
        console.error('Error fetching profile:', err);
      });
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setProfile(prev => ({ ...prev, [name]: value }));

    // Clear any error for this field when user starts typing
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: null }));
    }
  };

  const validateForm = () => {
    const newErrors = {};

    // Validate name
    if (!profile.fullName.trim()) {
      newErrors.fullName = 'Name is required';
    }

    // Validate email
    if (!profile.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!/\S+@\S+\.\S+/.test(profile.email)) {
      newErrors.email = 'Email is invalid';
    }

    // Validate mobile (if provided)
    if (profile.mobileNumber && !/^\d{10}$/.test(profile.mobileNumber.replace(/\D/g, ''))) {
      newErrors.mobileNumber = 'Please enter a valid 10-digit mobile number';
    }

    // Validate username
    if (!profile.username.trim()) {
      newErrors.username = 'Username is required';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    // In a real app, you would make an API call here
    console.log('Submitting updated profile:', profile);

    // Simulate API call success
    setTimeout(() => {
      setMessage({
        type: 'success',
        text: 'Profile updated successfully!'
      });

      // Clear message after 3 seconds
      setTimeout(() => {
        setMessage(null);
      }, 3000);
    }, 1500);
  };

  return (
    <div className="main-content">
      <div className="profile-container">
        <div className="profile-navigation">
          <h3>Your Account</h3>
          <ul>
            <li><Link to="/">Profile</Link></li>
            <li className="active"><Link to="/edit-profile">Edit Profile</Link></li>
            <li><Link to="/manage-addresses">Manage Addresses</Link></li>
            <li><Link to="/order-history">Order History</Link></li>
            <li><Link to="/payment-methods">Payment Methods</Link></li>
          </ul>
        </div>

        <div className="profile-edit-card">
          <h2>Edit Profile</h2>

          {message && (
            <div className={`message ${message.type}`}>
              {message.text}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label htmlFor="fullName">Full Name</label>
              <input 
                type="text"
                id="fullName"
                name="fullName"
                value={profile.fullName}
                onChange={handleChange}
                className={errors.fullName ? 'error' : ''}
              />
              {errors.fullName && <span className="error-text">{errors.fullName}</span>}
            </div>

            <div className="form-group">
              <label htmlFor="email">Email</label>
              <input 
                type="email"
                id="email"
                name="email"
                value={profile.email}
                onChange={handleChange}
                className={errors.email ? 'error' : ''}
              />
              {errors.email && <span className="error-text">{errors.email}</span>}
            </div>

            <div className="form-group">
              <label htmlFor="mobileNumber">Mobile Number</label>
              <input 
                type="tel"
                id="mobileNumber"
                name="mobileNumber"
                value={profile.mobileNumber}
                onChange={handleChange}
                placeholder="e.g., 555-123-4567"
                className={errors.mobileNumber ? 'error' : ''}
              />
              {errors.mobileNumber && <span className="error-text">{errors.mobileNumber}</span>}
            </div>

            <div className="form-group">
              <label htmlFor="username">Username</label>
              <input 
                type="text"
                id="username"
                name="username"
                value={profile.username}
                onChange={handleChange}
                className={errors.username ? 'error' : ''}
              />
              {errors.username && <span className="error-text">{errors.username}</span>}
            </div>

            <div className="form-group">
              <label htmlFor="password">Password</label>
              <div className="password-field">
                <input 
                  type="password"
                  id="password"
                  name="password"
                  value={profile.password}
                  disabled
                />
                <Link to="/change-password" className="change-password-link">Change</Link>
              </div>
            </div>

            <div className="form-actions">
              <button type="button" className="cancel-button" onClick={() => window.history.back()}>
                Cancel
              </button>
              <button type="submit" className="save-button">
                Save Changes
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

export default EditProfile;
